import React, { useState } from 'react';
import { uid } from './db';
import { toast } from './ui.jsx';

const CO_ACTIVITIES = [
  'General Knowledge','Art Education','Health & Physical Education',
  'Scientific Skills','Thinking Skills','Moral Education','Yoga / P.T.','Sports',
];
const DISCIPLINE_ITEMS = [
  'Regularity & Punctuality','Sincerity','Behavior & Values',
  'Respectfulness for Rules & Regulations','Attitude Towards Teachers',
  'Attitude Towards School-Mates','Attitude Towards Society','Attitude Towards Nation',
];
const GRADES_8 = ['A1','A2','B1','B2','C1','C2','D','E'];

const EARLY_SUBS = 'Hindi, English, Mathematics, Rhymes';
const UPPER_SUBS = 'English, Hindi, Mathematics, Science, S.St., Computer';

function defaultSubs(cls) {
  if (!cls) return '';
  const lower = cls.toLowerCase().replace(/\./g,'');
  if (['playgroup','nursery','lkg','ukg'].includes(lower)) return EARLY_SUBS;
  const m = lower.match(/^(\d+)(st|nd|rd|th)?$/);
  if (m && parseInt(m[1]) >= 1 && parseInt(m[1]) <= 8) return UPPER_SUBS;
  return '';
}

function grade8(pct) {
  if (pct >= 91) return 'A1'; if (pct >= 81) return 'A2';
  if (pct >= 71) return 'B1'; if (pct >= 61) return 'B2';
  if (pct >= 51) return 'C1'; if (pct >= 41) return 'C2';
  if (pct >= 33) return 'D'; return 'E';
}
function gradeColor(g) {
  return {A1:'#166534',A2:'#065f46',B1:'#1e40af',B2:'#1d4ed8',C1:'#92400e',C2:'#b45309',D:'#c2410c',E:'#991b1b'}[g]||'#374151';
}
function gradeBg(g) {
  return {A1:'#dcfce7',A2:'#d1fae5',B1:'#dbeafe',B2:'#eff6ff',C1:'#fef3c7',C2:'#fffbeb',D:'#ffedd5',E:'#fee2e2'}[g]||'#f3f4f6';
}

const GradeSelect = ({ value, onChange }) => (
  <select value={value||'A2'} onChange={e=>onChange(e.target.value)}
    style={{fontSize:11,fontWeight:700,padding:'2px 5px',borderRadius:5,border:'1px solid #bfdbfe',
      background:gradeBg(value||'A2'),color:gradeColor(value||'A2'),cursor:'pointer',outline:'none'}}>
    {GRADES_8.map(g=><option key={g} value={g}>{g}</option>)}
  </select>
);

// ── Guest student form (not in directory) ────────────────────────
const BLANK_GUEST = { fn:'', ln:'', father:'', mother:'', dob:'', roll:'', admNo:'', gn:'Male', blood:'', addr:'', cls:'' };

function GuestForm({ guest, setGuest, subjects, setSubjects, marks, setMarks }) {
  const f = (k) => (v) => setGuest(g => ({...g, [k]: v}));
  const inp = 'w-full p-2.5 bg-blue-50 border border-blue-200 rounded-xl text-sm text-slate-700 focus:ring-2 focus:ring-blue-300 outline-none';
  const lbl = 'block text-xs font-bold text-slate-500 mb-1 uppercase tracking-wider';

  return (
    <div className="space-y-5">
      <div className="grid grid-cols-2 gap-4">
        {[['First Name','fn'],['Last Name','ln'],["Father's Name",'father'],["Mother's Name",'mother'],
          ['Date of Birth','dob'],['Roll No.','roll'],['Admission No.','admNo'],['Blood Group','blood'],
        ].map(([label,key])=>(
          <div key={key}>
            <label className={lbl}>{label}</label>
            <input value={guest[key]||''} onChange={e=>f(key)(e.target.value)} className={inp} placeholder={label}/>
          </div>
        ))}
        <div>
          <label className={lbl}>Gender</label>
          <select value={guest.gn||'Male'} onChange={e=>f('gn')(e.target.value)} className={inp}>
            {['Male','Female','Other'].map(g=><option key={g}>{g}</option>)}
          </select>
        </div>
        <div className="col-span-2">
          <label className={lbl}>Address</label>
          <input value={guest.addr||''} onChange={e=>f('addr')(e.target.value)} className={inp} placeholder="Address"/>
        </div>
      </div>

      <div>
        <label className={lbl}>Subjects (comma separated)</label>
        <input value={subjects} onChange={e=>setSubjects(e.target.value)} className={inp}
          placeholder="Hindi, English, Mathematics, Rhymes"/>
        <p className="text-xs text-slate-400 mt-1">These subjects will appear as rows in the marksheet.</p>
      </div>

      <div>
        <p className={lbl + ' mb-3'}>Marks Entry</p>
        <div className="space-y-2">
          {subjects.split(',').map(s=>s.trim()).filter(Boolean).map(su => {
            const m = marks[su] || {};
            return (
              <div key={su} className="bg-blue-50 rounded-xl p-3 border border-blue-100">
                <p className="text-xs font-bold text-blue-700 mb-2">{su}</p>
                <div className="grid grid-cols-5 gap-2">
                  {[['T1 Per.Test','t1_pt'],['T1 NoteBook','t1_nb'],['T1 SEA','t1_sea'],['T1 Half Yearly','t1_hy'],
                    ['T2 Per.Test','t2_pt'],['T2 NoteBook','t2_nb'],['T2 SEA','t2_sea'],['T2 Yearly','t2_ye'],
                  ].map(([label,key])=>(
                    <div key={key}>
                      <label className="block text-[9px] font-bold text-slate-400 mb-1">{label}</label>
                      <input type="number" min="0" value={m[key]??''} onChange={e=>setMarks(mk=>({...mk,[su]:{...mk[su],[key]:e.target.value===''?null:parseFloat(e.target.value)}}))}
                        className="w-full p-1.5 bg-white border border-blue-200 rounded-lg text-xs text-center text-slate-700 outline-none focus:ring-1 focus:ring-blue-300"/>
                    </div>
                  ))}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

export default function ReportCardStudio({ db, logo }) {
  const classes = db.classes.map(c => c.name);
  const [mode, setMode] = useState('directory'); // 'directory' | 'guest'
  const [rcCls, setRcCls] = useState('');
  const [selStu, setSelStu] = useState('all');
  const [overrides, setOverrides] = useState({});
  const [activeTab, setActiveTab] = useState('info');

  // Guest mode state
  const [guest, setGuest] = useState(BLANK_GUEST);
  const [guestSubjects, setGuestSubjects] = useState('');
  const [guestMarks, setGuestMarks] = useState({});
  const [guestCoGrades, setGuestCoGrades] = useState({});
  const [guestDiscGrades, setGuestDiscGrades] = useState({});
  const [guestAttP, setGuestAttP] = useState('');
  const [guestAttT, setGuestAttT] = useState('');
  const [guestTab, setGuestTab] = useState('info');

  const clsStudents = rcCls ? db.students.filter(s => s.cls === rcCls) : [];
  const editStu = selStu !== 'all' ? db.students.find(s => s.id === selStu) : null;

  const getOvr = (sid) => overrides[sid] || {};
  const setOvr = (sid, patch) => setOverrides(o => ({ ...o, [sid]: { ...(o[sid]||{}), ...patch } }));
  const setCoGrade = (sid, act, g) => setOvr(sid, { coGrades: { ...(getOvr(sid).coGrades||{}), [act]: g } });
  const setDiscGrade = (sid, item, g) => setOvr(sid, { discGrades: { ...(getOvr(sid).discGrades||{}), [item]: g } });

  const getAtt = (sid) => {
    let p = 0, t = 0;
    Object.values(db.att).forEach(d => { if (d[sid]!==undefined){t++;if(d[sid]==='P'||d[sid]==='L')p++;} });
    return { p, t };
  };

  const clsExams = db.exams.filter(e => !e.cls || e.cls === rcCls);
  const t1Exams  = clsExams.filter(e => e.term === 'Term1');
  const t2Exams  = clsExams.filter(e => e.term === 'Term2');
  const subjects = rcCls
    ? ((db.classes.find(c=>c.name===rcCls)?.subs || defaultSubs(rcCls) || '').split(',').map(s=>s.trim()).filter(Boolean))
    : [];

  const getMark = (examId, sid) => { const v=(db.marks[examId+'_'+rcCls]||{})[sid]; return v!==undefined?v:null; };
  const getSubjectExams = (su, termExams) => termExams.filter(e => e.su === su);

  const autoGrades = (sid) => {
    let total=0,count=0;
    subjects.forEach(su=>{
      const t1=getSubjectExams(su,t1Exams),t2=getSubjectExams(su,t2Exams);
      const t1T=t1.length===1?getMark(t1[0].id,sid):null,t2T=t2.length===1?getMark(t2[0].id,sid):null;
      const t1M=t1.reduce((a,e)=>a+(e.max||0),0)||100,t2M=t2.reduce((a,e)=>a+(e.max||0),0)||100;
      const t1H=t1T!==null?Math.round(t1T/t1M*50):null,t2H=t2T!==null?Math.round(t2T/t2M*50):null;
      if(t1H!==null&&t2H!==null){total+=t1H+t2H;count++;}
    });
    const avg=count>0?Math.round(total/count):50;
    const g=grade8(avg);
    return { coGrades:Object.fromEntries(CO_ACTIVITIES.map(a=>[a,g])), discGrades:Object.fromEntries(DISCIPLINE_ITEMS.map(d=>[d,g])) };
  };

  const applyAutoGrades = (sid) => { setOvr(sid, autoGrades(sid)); toast('Grades auto-filled'); };
  const applyAutoGradesAll = () => { clsStudents.forEach(s=>setOverrides(o=>({...o,[s.id]:{...(o[s.id]||{}),...autoGrades(s.id)}}))); toast('Auto-filled all students'); };

  // Auto-fill guest co/disc from guest marks
  const autoGuestGrades = () => {
    const subs = guestSubjects.split(',').map(s=>s.trim()).filter(Boolean);
    let total=0,count=0;
    subs.forEach(su=>{
      const m=guestMarks[su]||{};
      const t1T=(m.t1_pt||0)+(m.t1_nb||0)+(m.t1_sea||0)+(m.t1_hy||0);
      const t2T=(m.t2_pt||0)+(m.t2_nb||0)+(m.t2_sea||0)+(m.t2_ye||0);
      if(t1T||t2T){total+=Math.round(t1T/100*50)+Math.round(t2T/100*50);count++;}
    });
    const avg=count>0?Math.round(total/count):50;
    const g=grade8(avg);
    setGuestCoGrades(Object.fromEntries(CO_ACTIVITIES.map(a=>[a,g])));
    setGuestDiscGrades(Object.fromEntries(DISCIPLINE_ITEMS.map(d=>[d,g])));
    toast('Guest grades auto-filled');
  };

  // ── HTML generator (shared for both directory and guest) ─────────
  const buildRC = (students, opts = {}) => {
    const school = db.settings.school || 'LORD KRISHNA PUBLIC SCHOOL';
    const yr     = db.settings.year   || '2025-2026';
    const addr   = db.settings.addr   || '';
    const prin   = db.settings.prin   || '';
    const phone  = db.settings.phone  || '';
    const cls    = opts.cls || rcCls;

    const css = `
      *{box-sizing:border-box;margin:0;padding:0}
      html,body{width:210mm;background:#e8edf2;-webkit-print-color-adjust:exact;print-color-adjust:exact;font-family:Arial,Helvetica,sans-serif}
      .page{width:210mm;height:297mm;margin:0 auto 12px;background:#fff;display:flex;flex-direction:column;position:relative;overflow:hidden;page-break-after:always;page-break-inside:avoid;box-shadow:0 2px 20px rgba(0,0,0,0.12)}
      .page::before{content:'';position:absolute;left:0;top:0;bottom:0;width:4px;background:linear-gradient(180deg,#2563eb,#0ea5e9);z-index:10}
      .wm{position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);width:240px;height:240px;opacity:0.035;pointer-events:none;z-index:0;object-fit:contain}
      .hdr{background:linear-gradient(135deg,#eff6ff 0%,#dbeafe 55%,#e0f2fe 100%);padding:10px 20px 8px 24px;display:flex;align-items:center;gap:14px;border-bottom:2px solid #bfdbfe;flex-shrink:0}
      .hdr-logo{width:50px;height:50px;border-radius:50%;border:2px solid #93c5fd;overflow:hidden;flex-shrink:0;background:#fff;display:flex;align-items:center;justify-content:center}
      .hdr-logo img{width:100%;height:100%;object-fit:contain}
      .hdr-logo-fb{font-size:20px;font-weight:900;color:#1e40af;font-family:serif}
      .hdr-text{flex:1;text-align:center}
      .hdr-school{font-size:15px;font-weight:900;color:#1e3a8a;letter-spacing:0.8px;text-transform:uppercase}
      .hdr-addr{font-size:8.5px;color:#3b82f6;margin-top:1px}
      .hdr-title{display:inline-block;margin-top:6px;background:#dbeafe;border:1px solid #93c5fd;border-radius:20px;padding:2px 14px;font-size:10px;font-weight:800;color:#1e40af;letter-spacing:0.8px;text-transform:uppercase}
      .hdr-badge{flex-shrink:0;text-align:center}
      .hdr-cls-box{background:#fff;border:1.5px solid #93c5fd;border-radius:8px;padding:4px 12px}
      .hdr-cls-lbl{font-size:7.5px;color:#3b82f6;text-transform:uppercase;letter-spacing:0.8px;font-weight:700}
      .hdr-cls-val{font-size:15px;font-weight:900;color:#1e3a8a;line-height:1.1}
      .hdr-yr{font-size:8.5px;color:#64748b;margin-top:4px}
      .info{background:#f8faff;border-bottom:1px solid #e2e8f0;padding:7px 20px 7px 24px;display:grid;grid-template-columns:1fr 1fr;gap:0 30px;flex-shrink:0}
      .ir{display:flex;align-items:baseline;padding:2.5px 0;border-bottom:1px dashed #e2e8f0}
      .ir:last-child{border-bottom:none}
      .il{font-size:9px;font-weight:700;color:#3b82f6;min-width:100px;flex-shrink:0}
      .iv{font-size:9.5px;color:#1e293b;font-weight:500}
      .tw{padding-left:4px;flex-shrink:0}
      .mt{width:100%;border-collapse:collapse}
      .mt th,.mt td{border:1px solid #bfdbfe;text-align:center;line-height:1.2}
      .th-a{background:#dbeafe;color:#1e3a8a;font-weight:800;text-align:left;padding-left:7px}
      .th-t{background:#eff6ff;color:#1e40af;font-weight:800;border-bottom:2px solid #93c5fd}
      .th-o{background:#e0f2fe;color:#0369a1;font-weight:800;border-bottom:2px solid #7dd3fc}
      .th-s{background:#f8faff;color:#475569;font-weight:700}
      .th-m{background:#fdf2f8;color:#9d174d;font-weight:800}
      .td-s{text-align:left;padding-left:7px;font-weight:700;color:#1e40af;background:#f0f6ff}
      .td-tot{background:#eff6ff;font-weight:800;color:#1e40af}
      .td-g{background:#f0fdf4;font-weight:900;color:#166534}
      .td-r{font-weight:700;color:#7c3aed}
      tr:nth-child(even) td:not(.td-s):not(.td-tot):not(.td-g){background:#f8faff}
      .gb{border-radius:3px;padding:1px 3px;font-weight:900}
      .gn{background:#f8faff;border-top:1px solid #e2e8f0;border-bottom:1px solid #e2e8f0;padding:4px 20px 4px 24px;color:#64748b;font-style:italic;line-height:1.4;flex-shrink:0}
      .tb{background:linear-gradient(90deg,#f0f6ff,#e0f2fe);border-bottom:1px solid #bfdbfe;padding:6px 20px 6px 24px;display:flex;align-items:center;gap:16px;flex-shrink:0}
      .ti{display:flex;align-items:center;gap:8px}
      .tl{font-weight:700;color:#1e40af}
      .tv{background:#fff;border:1.5px solid #93c5fd;border-radius:6px;padding:2px 12px;font-weight:900;color:#1e3a8a}
      .pb{flex:1;margin-left:6px}
      .pb-bg{height:6px;background:#dbeafe;border-radius:3px;overflow:hidden}
      .pb-fill{height:100%;border-radius:3px}
      .pb-lbl{color:#94a3b8;margin-top:1px;text-align:right}
      .cw{display:grid;grid-template-columns:1fr 1fr;flex:1;min-height:0;border-bottom:1px solid #e2e8f0}
      .ch{overflow:hidden;display:flex;flex-direction:column}
      .ch:first-child{border-right:1px solid #e2e8f0}
      .ct{width:100%;border-collapse:collapse;flex:1}
      .ct .chm{background:#eff6ff;color:#1e40af;font-weight:800;text-align:center;border-bottom:1.5px solid #bfdbfe}
      .ct .chs{background:#f8faff;color:#475569;font-weight:700;border:1px solid #e2e8f0;text-align:center}
      .ct td{border:1px solid #e2e8f0}
      .ca{text-align:left;color:#1e293b}
      .cg{text-align:center;font-weight:800}
      .ft{padding:6px 20px 10px 24px;flex-shrink:0}
      .ft-top{display:flex;justify-content:space-between;align-items:center;margin-bottom:4px}
      .att-b{display:inline-flex;align-items:center;gap:4px;background:#eff6ff;border:1px solid #bfdbfe;border-radius:5px;padding:2px 9px;font-weight:700;color:#1e40af}
      .rm-b{display:inline-flex;align-items:center;gap:4px;border-radius:5px;padding:2px 9px;font-weight:700}
      .rm-g{background:#f0fdf4;color:#166534;border:1px solid #bbf7d0}
      .rm-o{background:#fffbeb;color:#92400e;border:1px solid #fde68a}
      .rm-r{background:#fef2f2;color:#991b1b;border:1px solid #fecaca}
      .promo{color:#475569;font-style:italic}
      .sr{display:flex;justify-content:space-between;padding-top:10px;border-top:1px solid #e5e7eb;margin-top:4px}
      .si{text-align:center;min-width:90px}
      .sl{border-top:1.5px solid #374151;padding-top:3px;color:#374151;font-weight:600}
      @media print{@page{size:A4 portrait;margin:0}html,body{background:#fff;width:210mm}.page{box-shadow:none;margin:0;page-break-after:always;page-break-inside:avoid}}
    `;

    const perfColor = pct => pct>=75?'#22c55e':pct>=50?'#f59e0b':'#ef4444';
    const fmt = v => v!==null&&v!==undefined?v:'—';
    const gBadge = (g,fs) => g!=='—'?`<span class="gb" style="color:${gradeColor(g)};background:${gradeBg(g)};font-size:${fs}px">${g}</span>`:'—';
    const logoTag = logo ? `<img src="${logo}" class="wm" alt=""/>` : '';

    const w = window.open('', '_blank');
    let html = `<!DOCTYPE html><html><head><meta charset="utf-8"><title>Report Cards — ${cls}</title><style>${css}</style></head><body>`;

    students.forEach(entry => {
      const s    = entry.s;
      const subs = entry.subjects;
      const attP = entry.attP;
      const attT = entry.attT;
      const coG  = entry.coGrades  || {};
      const dG   = entry.discGrades || {};
      const rank = entry.rank;

      const subCount = subs.length;
      const tblFs   = subCount <= 4 ? 11   : subCount <= 6 ? 10   : 9;
      const cellPad = subCount <= 4 ? 5    : subCount <= 6 ? 4    : 3;
      const coFs    = subCount <= 4 ? 10.5 : subCount <= 6 ? 10   : 9.5;
      const gnFs    = subCount <= 4 ? 8.5  : 8;
      const tbFs    = subCount <= 4 ? 10.5 : 10;
      const ftFs    = subCount <= 4 ? 10.5 : 10;
      const sigMt   = subCount <= 4 ? 22   : 16;

      const subjectRows = subs.map(su => {
        const m = entry.marks[su] || {};
        const t1_pt=m.t1_pt??null,t1_nb=m.t1_nb??null,t1_sea=m.t1_sea??null,t1_hy=m.t1_hy??null;
        const t2_pt=m.t2_pt??null,t2_nb=m.t2_nb??null,t2_sea=m.t2_sea??null,t2_ye=m.t2_ye??null;
        const t1Total=(t1_pt!==null||t1_nb!==null||t1_sea!==null||t1_hy!==null)?(t1_pt||0)+(t1_nb||0)+(t1_sea||0)+(t1_hy||0):null;
        const t2Total=(t2_pt!==null||t2_nb!==null||t2_sea!==null||t2_ye!==null)?(t2_pt||0)+(t2_nb||0)+(t2_sea||0)+(t2_ye||0):null;
        const t1Half=t1Total!==null?Math.round(t1Total/100*50):null;
        const t2Half=t2Total!==null?Math.round(t2Total/100*50):null;
        const grand=(t1Half!==null&&t2Half!==null)?t1Half+t2Half:null;
        return {su,t1_pt,t1_nb,t1_sea,t1_hy,t1Total,t2_pt,t2_nb,t2_sea,t2_ye,t2Total,grand};
      });

      const validRows    = subjectRows.filter(r=>r.grand!==null);
      const overallTotal = validRows.reduce((a,r)=>a+(r.grand||0),0);
      const overallMax   = validRows.length*100;
      const overallPct   = overallMax>0?Math.round(overallTotal/overallMax*100):0;
      const remarkCls    = overallPct>=75?'rm-g':overallPct>=50?'rm-o':'rm-r';
      const remarkText   = overallPct>=75?'Good!':overallPct>=50?'Satisfactory':'Needs Improvement';
      const barColor     = perfColor(overallPct);

      const cp  = `padding:${cellPad}px 2px`;
      const thP = `padding:${cellPad+1}px 2px`;

      const subRows = subjectRows.map(r => {
        const g = r.grand!==null?grade8(r.grand):'—';
        return `<tr style="font-size:${tblFs}px">
          <td class="td-s" style="${cp};font-size:${tblFs}px">${r.su}</td>
          <td style="${cp}">${fmt(r.t1_pt)}</td><td style="${cp}">${fmt(r.t1_nb)}</td>
          <td style="${cp}">${fmt(r.t1_sea)}</td><td style="${cp}">${fmt(r.t1_hy)}</td>
          <td class="td-tot" style="${cp}">${fmt(r.t1Total)}</td>
          <td style="${cp}">${fmt(r.t2_pt)}</td><td style="${cp}">${fmt(r.t2_nb)}</td>
          <td style="${cp}">${fmt(r.t2_sea)}</td><td style="${cp}">${fmt(r.t2_ye)}</td>
          <td class="td-tot" style="${cp}">${fmt(r.t2Total)}</td>
          <td class="td-g" style="${cp};font-size:${tblFs+1}px">${fmt(r.grand)}</td>
          <td style="${cp}">${gBadge(g,tblFs)}</td>
          <td class="td-r" style="${cp}">${rank>0&&r.grand!==null?rank:'—'}</td>
        </tr>`;
      }).join('');

      const coRows   = CO_ACTIVITIES.map(a=>{const g=coG[a]||'A2';return`<tr><td class="ca" style="padding:${cellPad}px 7px;font-size:${coFs}px">${a}</td><td class="cg" style="padding:${cellPad}px 4px;font-size:${coFs}px;color:${gradeColor(g)}">${g}</td><td class="cg" style="padding:${cellPad}px 4px;font-size:${coFs}px;color:${gradeColor(g)}">${g}</td></tr>`;}).join('');
      const discRows = DISCIPLINE_ITEMS.map(d=>{const g=dG[d]||'A2';return`<tr><td class="ca" style="padding:${cellPad}px 7px;font-size:${coFs-0.5}px">${d}</td><td class="cg" style="padding:${cellPad}px 4px;font-size:${coFs}px;color:${gradeColor(g)}">${g}</td><td class="cg" style="padding:${cellPad}px 4px;font-size:${coFs}px;color:${gradeColor(g)}">${g}</td></tr>`;}).join('');

      html+=`
      <div class="page">
        ${logoTag}
        <div class="hdr">
          <div class="hdr-logo">${logo?`<img src="${logo}" alt=""/>`:`<span class="hdr-logo-fb">${school.charAt(0)}</span>`}</div>
          <div class="hdr-text">
            <div class="hdr-school">${school}</div>
            <div class="hdr-addr">${addr}${phone?' &nbsp;|&nbsp; Ph: '+phone:''}</div>
            <div class="hdr-title">Report Card</div>
          </div>
          <div class="hdr-badge">
            <div class="hdr-cls-box"><div class="hdr-cls-lbl">Class</div><div class="hdr-cls-val">${cls}</div></div>
            <div class="hdr-yr">Session: ${yr}</div>
          </div>
        </div>
        <div class="info">
          <div>
            <div class="ir"><span class="il">Student's Name</span><span class="iv">${s.fn} ${s.ln}</span></div>
            <div class="ir"><span class="il">Father's Name</span><span class="iv">${s.father||'—'}</span></div>
            <div class="ir"><span class="il">Mother's Name</span><span class="iv">${s.mother||'—'}</span></div>
            <div class="ir"><span class="il">Date of Birth</span><span class="iv">${s.dob||'—'}</span></div>
            <div class="ir"><span class="il">Address</span><span class="iv">${s.addr||addr||'—'}</span></div>
          </div>
          <div>
            <div class="ir"><span class="il">Roll No.</span><span class="iv">${s.roll||'—'}</span></div>
            <div class="ir"><span class="il">Admission No.</span><span class="iv">${s.admNo||'—'}</span></div>
            <div class="ir"><span class="il">Gender</span><span class="iv">${s.gn||'—'}</span></div>
            <div class="ir"><span class="il">Blood Group</span><span class="iv">${s.blood||'—'}</span></div>
          </div>
        </div>
        <div class="tw">
          <table class="mt">
            <thead>
              <tr>
                <th rowspan="3" class="th-a" style="${thP};width:80px;font-size:${tblFs}px">Scholastic<br/>Area</th>
                <th colspan="5" class="th-t" style="${thP};font-size:${tblFs+1}px">Term 1 &nbsp;(100 Marks)</th>
                <th colspan="5" class="th-t" style="${thP};font-size:${tblFs+1}px">Term 2 &nbsp;(100 Marks)</th>
                <th colspan="3" class="th-o" style="${thP};font-size:${tblFs}px">Overall</th>
              </tr>
              <tr>
                <th colspan="5" class="th-s" style="padding:2px;font-size:7.5px;color:#94a3b8">Per.Test + Notebook + SEA + Half Yearly</th>
                <th colspan="5" class="th-s" style="padding:2px;font-size:7.5px;color:#94a3b8">Per.Test + Notebook + SEA + Yearly Exam</th>
                <th colspan="3" class="th-s" style="padding:2px;font-size:7.5px">T1(50)+T2(50)</th>
              </tr>
              <tr class="th-s" style="font-size:${tblFs-1}px">
                <th style="${thP}">Per.<br/>Test</th><th style="${thP}">Note<br/>Book</th>
                <th style="${thP}">SEA</th><th style="${thP}">Half<br/>Yearly</th><th style="${thP}">Total</th>
                <th style="${thP}">Per.<br/>Test</th><th style="${thP}">Note<br/>Book</th>
                <th style="${thP}">SEA</th><th style="${thP}">Yearly<br/>Exam</th><th style="${thP}">Total</th>
                <th style="${thP}">Grand<br/>Total</th><th style="${thP}">Grade</th><th style="${thP}">Rank</th>
              </tr>
              <tr class="th-m" style="font-size:${tblFs-1}px">
                <td class="td-s" style="${thP};font-size:${tblFs-1}px">Subjects</td>
                <td style="${thP}">10</td><td style="${thP}">5</td><td style="${thP}">5</td><td style="${thP}">80</td><td style="${thP}">100</td>
                <td style="${thP}">10</td><td style="${thP}">5</td><td style="${thP}">5</td><td style="${thP}">80</td><td style="${thP}">100</td>
                <td style="${thP}">100</td><td style="${thP}"></td><td style="${thP}"></td>
              </tr>
            </thead>
            <tbody>${subRows||`<tr><td colspan="14" style="text-align:center;padding:10px;color:#94a3b8;font-style:italic;font-size:${tblFs}px">No marks entered</td></tr>`}</tbody>
          </table>
        </div>
        <div class="gn" style="font-size:${gnFs}px">
          <strong>8-Point Scale:</strong>&nbsp;A1(91-100%) A2(81-90%) B1(71-80%) B2(61-70%) C1(51-60%) C2(41-50%) D(33-40%) E(≤32%)&nbsp;&nbsp;<strong>*SEA</strong>=Sub Enrichment Activity
        </div>
        <div class="tb" style="font-size:${tbFs}px">
          <div class="ti"><span class="tl" style="font-size:${tbFs}px">Overall Marks</span><span class="tv" style="font-size:${tbFs+1}px">${overallTotal} / ${overallMax}</span></div>
          <div class="ti"><span class="tl" style="font-size:${tbFs}px">Percentage</span><span class="tv" style="font-size:${tbFs+1}px">${overallPct}%</span></div>
          <div class="pb"><div class="pb-bg"><div class="pb-fill" style="width:${overallPct}%;background:${barColor}"></div></div><div class="pb-lbl" style="font-size:${gnFs}px">${overallPct}% — ${remarkText}</div></div>
        </div>
        <div class="cw">
          <div class="ch">
            <table class="ct" style="height:100%">
              <thead>
                <tr><td colspan="3" class="chm" style="padding:${cellPad+1}px 8px;font-size:${coFs+0.5}px">Co-Scholastic Areas</td></tr>
                <tr><th class="chs" style="text-align:left;padding:${cellPad}px 8px;font-size:${coFs-1}px">Activity</th><th class="chs" style="padding:${cellPad}px 4px;font-size:${coFs-1}px">T1</th><th class="chs" style="padding:${cellPad}px 4px;font-size:${coFs-1}px">T2</th></tr>
              </thead>
              <tbody>${coRows}</tbody>
            </table>
          </div>
          <div class="ch">
            <table class="ct" style="height:100%">
              <thead>
                <tr><td colspan="3" class="chm" style="padding:${cellPad+1}px 8px;font-size:${coFs+0.5}px">Discipline</td></tr>
                <tr><th class="chs" style="text-align:left;padding:${cellPad}px 8px;font-size:${coFs-1}px">Element</th><th class="chs" style="padding:${cellPad}px 4px;font-size:${coFs-1}px">T1</th><th class="chs" style="padding:${cellPad}px 4px;font-size:${coFs-1}px">T2</th></tr>
              </thead>
              <tbody>${discRows}</tbody>
            </table>
          </div>
        </div>
        <div class="ft">
          <div class="ft-top">
            <span class="att-b" style="font-size:${ftFs}px">Attendance : ${attP} / ${attT} days</span>
            <span class="rm-b ${remarkCls}" style="font-size:${ftFs}px">Remarks : ${remarkText}</span>
          </div>
          <div class="promo" style="font-size:${ftFs-0.5}px;margin-bottom:4px">${overallPct>=33?`Congratulations! Promoted to Class ${cls}.`:'Result: Detained — Please contact the school.'}</div>
          <div class="sr">
            <div class="si"><div class="sl" style="font-size:${ftFs-1}px;margin-top:${sigMt}px">Date : ${new Date().toLocaleDateString('en-IN')}</div></div>
            <div class="si"><div class="sl" style="font-size:${ftFs-1}px;margin-top:${sigMt}px">Class Teacher</div></div>
            <div class="si"><div class="sl" style="font-size:${ftFs-1}px;margin-top:${sigMt}px">Principal${prin?' ('+prin+')':''}</div></div>
            <div class="si"><div class="sl" style="font-size:${ftFs-1}px;margin-top:${sigMt}px">Parent / Guardian</div></div>
          </div>
        </div>
      </div>`;
    });

    html += `<script>window.onload=()=>window.print()<\/script></body></html>`;
    w.document.write(html); w.document.close();
    toast('Report card generated');
  };

  // Build entries for directory students
  const buildDirectoryEntries = (studentsToGen) => {
    return studentsToGen.map(s => {
      const ovr = overrides[s.id] || {};
      const dbAtt = getAtt(s.id);
      const attP = ovr.attP !== undefined ? ovr.attP : dbAtt.p;
      const attT = ovr.attT !== undefined ? ovr.attT : dbAtt.t;

      const marks = {};
      subjects.forEach(su => {
        const t1 = getSubjectExams(su, t1Exams);
        const t2 = getSubjectExams(su, t2Exams);
        const fc = (exams, kws) => { const e=exams.find(ex=>kws.some(k=>ex.name.toLowerCase().includes(k))); return e?getMark(e.id,s.id):null; };
        marks[su] = {
          t1_pt: fc(t1,['per.test','periodic','per test','pt']),
          t1_nb: fc(t1,['note','notebook','note book']),
          t1_sea: fc(t1,['sea','sub enrich','enrichment']),
          t1_hy: fc(t1,['half','half yearly','hy']),
          t2_pt: fc(t2,['per.test','periodic','per test','pt']),
          t2_nb: fc(t2,['note','notebook','note book']),
          t2_sea: fc(t2,['sea','sub enrich','enrichment']),
          t2_ye: fc(t2,['yearly','annual','year exam','ye']),
        };
      });

      // Rank
      const classScores = clsStudents.map(st => subjects.reduce((sum,su)=>{
        const t1=getSubjectExams(su,t1Exams),t2=getSubjectExams(su,t2Exams);
        const t1T=t1.length===1?getMark(t1[0].id,st.id):null,t2T=t2.length===1?getMark(t2[0].id,st.id):null;
        const t1M=t1.reduce((a,e)=>a+(e.max||0),0)||100,t2M=t2.reduce((a,e)=>a+(e.max||0),0)||100;
        return sum+(t1T!==null?Math.round(t1T/t1M*50):0)+(t2T!==null?Math.round(t2T/t2M*50):0);
      },0)).sort((a,b)=>b-a);
      const myScore = subjects.reduce((sum,su)=>{
        const t1=getSubjectExams(su,t1Exams),t2=getSubjectExams(su,t2Exams);
        const t1T=t1.length===1?getMark(t1[0].id,s.id):null,t2T=t2.length===1?getMark(t2[0].id,s.id):null;
        const t1M=t1.reduce((a,e)=>a+(e.max||0),0)||100,t2M=t2.reduce((a,e)=>a+(e.max||0),0)||100;
        return sum+(t1T!==null?Math.round(t1T/t1M*50):0)+(t2T!==null?Math.round(t2T/t2M*50):0);
      },0);
      const rank = classScores.indexOf(myScore)+1;

      return { s: { ...s, addr: ovr.addr||s.addr }, subjects, marks, attP, attT, coGrades: ovr.coGrades||{}, discGrades: ovr.discGrades||{}, rank };
    });
  };

  const genDirectory = (studentsToGen) => {
    if (!rcCls) { toast('Select a class first','err'); return; }
    buildRC(buildDirectoryEntries(studentsToGen), { cls: rcCls });
  };

  const genGuest = () => {
    if (!guest.fn.trim()) { toast('Enter student first name','err'); return; }
    if (!guest.cls.trim()) { toast('Enter class name','err'); return; }
    const subs = guestSubjects.split(',').map(s=>s.trim()).filter(Boolean);
    if (!subs.length) { toast('Enter at least one subject','err'); return; }
    const entry = {
      s: { ...guest, id: 'guest' },
      subjects: subs,
      marks: guestMarks,
      attP: parseInt(guestAttP)||0,
      attT: parseInt(guestAttT)||0,
      coGrades: guestCoGrades,
      discGrades: guestDiscGrades,
      rank: 0,
    };
    buildRC([entry], { cls: guest.cls });
  };

  const inp = 'w-full p-2.5 bg-blue-50 border border-blue-200 rounded-xl text-sm text-slate-700 focus:ring-2 focus:ring-blue-300 outline-none';
  const lbl = 'block text-xs font-bold text-slate-500 mb-1 uppercase tracking-wider';

  return (
    <div className="space-y-6">
      {/* Mode toggle */}
      <div className="flex gap-2 bg-slate-100 p-1 rounded-xl w-fit">
        {[['directory','group','From Student Directory'],['guest','person_add','Guest Student (Manual)']].map(([id,icon,label])=>(
          <button key={id} onClick={()=>setMode(id)}
            className={`flex items-center gap-2 px-5 py-2.5 rounded-lg text-sm font-bold transition-all border-0 cursor-pointer ${mode===id?'bg-white text-blue-700 shadow-sm':'text-slate-500 bg-transparent hover:text-slate-700'}`}>
            <span className="material-symbols-outlined text-base">{icon}</span>{label}
          </button>
        ))}
      </div>

      {/* ── DIRECTORY MODE ── */}
      {mode === 'directory' && (
        <>
          <div className="bg-white rounded-2xl p-6 shadow-sm border border-blue-100">
            <p className="text-xs font-bold uppercase tracking-widest text-blue-400 mb-4">Configuration</p>
            <div className="flex flex-wrap gap-4 items-end">
              <div>
                <label className={lbl}>Class</label>
                <select value={rcCls} onChange={e=>{setRcCls(e.target.value);setSelStu('all');}}
                  className={inp + ' min-w-[140px]'}>
                  <option value="">Select Class</option>
                  {classes.map(c=><option key={c}>{c}</option>)}
                </select>
              </div>
              {rcCls && (
                <div>
                  <label className={lbl}>Edit Student</label>
                  <select value={selStu} onChange={e=>setSelStu(e.target.value)}
                    className={inp + ' min-w-[180px]'}>
                    <option value="all">— All Students —</option>
                    {clsStudents.map(s=><option key={s.id} value={s.id}>{s.fn} {s.ln}</option>)}
                  </select>
                </div>
              )}
              {rcCls && selStu!=='all' && (
                <button onClick={()=>applyAutoGrades(selStu)}
                  className="px-4 py-2.5 bg-blue-50 border border-blue-200 text-blue-700 rounded-xl text-xs font-bold hover:bg-blue-100 transition-colors border-0 cursor-pointer">
                  Auto-fill from Marks
                </button>
              )}
              {rcCls && (
                <button onClick={applyAutoGradesAll}
                  className="px-4 py-2.5 bg-indigo-50 border border-indigo-200 text-indigo-700 rounded-xl text-xs font-bold hover:bg-indigo-100 transition-colors border-0 cursor-pointer">
                  Auto-fill All
                </button>
              )}
            </div>
          </div>

          {/* Per-student editor */}
          {rcCls && selStu!=='all' && editStu && (
            <div className="bg-white rounded-2xl shadow-sm border border-blue-100 overflow-hidden">
              <div className="flex border-b border-blue-100 bg-blue-50">
                {[['info','person','Student Info'],['co','star','Co-Scholastic'],['disc','verified','Discipline'],['att','calendar_today','Attendance']].map(([id,icon,label])=>(
                  <button key={id} onClick={()=>setActiveTab(id)}
                    className={`flex items-center gap-1.5 px-5 py-3 text-xs font-bold transition-all border-0 cursor-pointer ${activeTab===id?'bg-white text-blue-700 border-b-2 border-blue-500':'text-slate-500 hover:text-slate-700 bg-transparent'}`}>
                    <span className="material-symbols-outlined text-sm">{icon}</span>{label}
                  </button>
                ))}
              </div>
              <div className="p-6">
                {activeTab==='info' && (
                  <div className="grid grid-cols-2 gap-4">
                    {[['Address Override','addr'],['Admission No.','admNo']].map(([label,key])=>(
                      <div key={key}>
                        <label className={lbl}>{label}</label>
                        <input value={(overrides[selStu]||{})[key]||''} onChange={e=>setOvr(selStu,{[key]:e.target.value})} className={inp} placeholder={label}/>
                      </div>
                    ))}
                    <div className="col-span-2 text-xs text-slate-400 italic">Other info is pulled from the Students directory.</div>
                  </div>
                )}
                {activeTab==='co' && (
                  <div className="grid grid-cols-2 gap-3">
                    {CO_ACTIVITIES.map(act=>{
                      const g=(overrides[selStu]?.coGrades||{})[act]||'A2';
                      return <div key={act} className="flex items-center justify-between bg-blue-50 rounded-xl px-4 py-2.5 border border-blue-100">
                        <span className="text-sm text-slate-700 font-medium">{act}</span>
                        <GradeSelect value={g} onChange={v=>setCoGrade(selStu,act,v)}/>
                      </div>;
                    })}
                  </div>
                )}
                {activeTab==='disc' && (
                  <div className="grid grid-cols-2 gap-3">
                    {DISCIPLINE_ITEMS.map(item=>{
                      const g=(overrides[selStu]?.discGrades||{})[item]||'A2';
                      return <div key={item} className="flex items-center justify-between bg-blue-50 rounded-xl px-4 py-2.5 border border-blue-100">
                        <span className="text-xs text-slate-700 font-medium">{item}</span>
                        <GradeSelect value={g} onChange={v=>setDiscGrade(selStu,item,v)}/>
                      </div>;
                    })}
                  </div>
                )}
                {activeTab==='att' && (()=>{
                  const dbAtt=getAtt(selStu);
                  const ovr=overrides[selStu]||{};
                  const attP=ovr.attP!==undefined?ovr.attP:dbAtt.p;
                  const attT=ovr.attT!==undefined?ovr.attT:dbAtt.t;
                  return <div className="space-y-4">
                    <p className="text-xs text-slate-400 italic">Auto-calculated from records. Override if needed.</p>
                    <div className="flex gap-6 items-center bg-blue-50 rounded-xl p-4 border border-blue-100">
                      <span className="text-sm text-slate-500">From records: <strong className="text-blue-700">{dbAtt.p} / {dbAtt.t}</strong></span>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div><label className={lbl}>Days Present</label><input type="number" min="0" value={attP} onChange={e=>setOvr(selStu,{attP:parseInt(e.target.value)||0})} className={inp}/></div>
                      <div><label className={lbl}>Total Working Days</label><input type="number" min="0" value={attT} onChange={e=>setOvr(selStu,{attT:parseInt(e.target.value)||0})} className={inp}/></div>
                    </div>
                    <button onClick={()=>setOvr(selStu,{attP:undefined,attT:undefined})} className="text-xs text-slate-400 hover:text-red-500 transition-colors cursor-pointer border-0 bg-transparent">Reset to auto</button>
                  </div>;
                })()}
              </div>
            </div>
          )}

          {rcCls && (
            <div className="flex gap-4">
              <button onClick={()=>genDirectory(selStu==='all'?clsStudents:[editStu].filter(Boolean))}
                className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white rounded-xl font-bold text-sm shadow-lg hover:bg-blue-700 transition-colors border-0 cursor-pointer">
                <span className="material-symbols-outlined text-lg">description</span>
                {selStu==='all'?`Generate All (${clsStudents.length})`:'Generate This Student'}
              </button>
              {selStu!=='all' && (
                <button onClick={()=>genDirectory(clsStudents)}
                  className="flex items-center gap-2 px-6 py-3 bg-slate-100 text-slate-700 rounded-xl font-bold text-sm hover:bg-slate-200 transition-colors border border-slate-200 cursor-pointer">
                  <span className="material-symbols-outlined text-lg">group</span>
                  Generate Entire Class
                </button>
              )}
            </div>
          )}
          {!rcCls && <div className="flex flex-col items-center justify-center py-16 text-slate-400"><span className="material-symbols-outlined text-5xl mb-3 opacity-30">description</span><p className="font-medium">Select a class to begin</p></div>}
        </>
      )}

      {/* ── GUEST MODE ── */}
      {mode === 'guest' && (
        <div className="bg-white rounded-2xl shadow-sm border border-blue-100 overflow-hidden">
          <div className="flex border-b border-blue-100 bg-blue-50">
            {[['info','person','Student Info & Marks'],['co','star','Co-Scholastic'],['disc','verified','Discipline'],['att','calendar_today','Attendance']].map(([id,icon,label])=>(
              <button key={id} onClick={()=>setGuestTab(id)}
                className={`flex items-center gap-1.5 px-5 py-3 text-xs font-bold transition-all border-0 cursor-pointer ${guestTab===id?'bg-white text-blue-700 border-b-2 border-blue-500':'text-slate-500 hover:text-slate-700 bg-transparent'}`}>
                <span className="material-symbols-outlined text-sm">{icon}</span>{label}
              </button>
            ))}
          </div>
          <div className="p-6">
            {guestTab==='info' && (
              <div className="space-y-5">
                <div className="grid grid-cols-2 gap-4">
                  <div><label className={lbl}>Class *</label>
                    <input value={guest.cls} onChange={e=>{const v=e.target.value;setGuest(g=>({...g,cls:v}));if(!guestSubjects){const auto=defaultSubs(v);if(auto)setGuestSubjects(auto);}}} className={inp} placeholder="e.g. L.K.G. or 5th"/></div>
                  {[['First Name *','fn'],['Last Name','ln'],["Father's Name",'father'],["Mother's Name",'mother'],
                    ['Date of Birth','dob'],['Roll No.','roll'],['Admission No.','admNo'],['Blood Group','blood'],
                  ].map(([label,key])=>(
                    <div key={key}><label className={lbl}>{label}</label>
                      <input value={guest[key]||''} onChange={e=>setGuest(g=>({...g,[key]:e.target.value}))} className={inp} placeholder={label}/></div>
                  ))}
                  <div><label className={lbl}>Gender</label>
                    <select value={guest.gn||'Male'} onChange={e=>setGuest(g=>({...g,gn:e.target.value}))} className={inp}>
                      {['Male','Female','Other'].map(g=><option key={g}>{g}</option>)}
                    </select></div>
                  <div className="col-span-2"><label className={lbl}>Address</label>
                    <input value={guest.addr||''} onChange={e=>setGuest(g=>({...g,addr:e.target.value}))} className={inp} placeholder="Address"/></div>
                </div>
                <div>
                  <label className={lbl}>Subjects (comma separated)</label>
                  <input value={guestSubjects} onChange={e=>setGuestSubjects(e.target.value)} className={inp} placeholder="Hindi, English, Mathematics, Rhymes"/>
                </div>
                <div>
                  <p className={lbl + ' mb-3'}>Marks Entry</p>
                  <div className="space-y-3">
                    {guestSubjects.split(',').map(s=>s.trim()).filter(Boolean).map(su=>{
                      const m=guestMarks[su]||{};
                      return <div key={su} className="bg-blue-50 rounded-xl p-3 border border-blue-100">
                        <p className="text-xs font-bold text-blue-700 mb-2">{su}</p>
                        <div className="grid grid-cols-4 gap-2">
                          {[['T1 Per.Test','t1_pt'],['T1 NoteBook','t1_nb'],['T1 SEA','t1_sea'],['T1 Half Yearly','t1_hy'],
                            ['T2 Per.Test','t2_pt'],['T2 NoteBook','t2_nb'],['T2 SEA','t2_sea'],['T2 Yearly','t2_ye'],
                          ].map(([label,key])=>(
                            <div key={key}>
                              <label className="block text-[9px] font-bold text-slate-400 mb-1">{label}</label>
                              <input type="number" min="0" value={m[key]??''} onChange={e=>setGuestMarks(mk=>({...mk,[su]:{...mk[su],[key]:e.target.value===''?null:parseFloat(e.target.value)}}))}
                                className="w-full p-1.5 bg-white border border-blue-200 rounded-lg text-xs text-center text-slate-700 outline-none focus:ring-1 focus:ring-blue-300"/>
                            </div>
                          ))}
                        </div>
                      </div>;
                    })}
                  </div>
                </div>
              </div>
            )}
            {guestTab==='co' && (
              <div>
                <div className="flex justify-between items-center mb-4">
                  <p className="text-xs text-slate-400 italic">Set grades for co-scholastic activities.</p>
                  <button onClick={autoGuestGrades} className="px-3 py-1.5 bg-blue-50 border border-blue-200 text-blue-700 rounded-lg text-xs font-bold hover:bg-blue-100 cursor-pointer border-0">Auto-fill from Marks</button>
                </div>
                <div className="grid grid-cols-2 gap-3">
                  {CO_ACTIVITIES.map(act=>{
                    const g=guestCoGrades[act]||'A2';
                    return <div key={act} className="flex items-center justify-between bg-blue-50 rounded-xl px-4 py-2.5 border border-blue-100">
                      <span className="text-sm text-slate-700 font-medium">{act}</span>
                      <GradeSelect value={g} onChange={v=>setGuestCoGrades(c=>({...c,[act]:v}))}/>
                    </div>;
                  })}
                </div>
              </div>
            )}
            {guestTab==='disc' && (
              <div className="grid grid-cols-2 gap-3">
                {DISCIPLINE_ITEMS.map(item=>{
                  const g=guestDiscGrades[item]||'A2';
                  return <div key={item} className="flex items-center justify-between bg-blue-50 rounded-xl px-4 py-2.5 border border-blue-100">
                    <span className="text-xs text-slate-700 font-medium">{item}</span>
                    <GradeSelect value={g} onChange={v=>setGuestDiscGrades(c=>({...c,[item]:v}))}/>
                  </div>;
                })}
              </div>
            )}
            {guestTab==='att' && (
              <div className="grid grid-cols-2 gap-4">
                <div><label className={lbl}>Days Present</label><input type="number" min="0" value={guestAttP} onChange={e=>setGuestAttP(e.target.value)} className={inp} placeholder="0"/></div>
                <div><label className={lbl}>Total Working Days</label><input type="number" min="0" value={guestAttT} onChange={e=>setGuestAttT(e.target.value)} className={inp} placeholder="0"/></div>
              </div>
            )}
          </div>
          <div className="px-6 pb-6">
            <button onClick={genGuest}
              className="flex items-center gap-2 px-6 py-3 bg-blue-600 text-white rounded-xl font-bold text-sm shadow-lg hover:bg-blue-700 transition-colors border-0 cursor-pointer">
              <span className="material-symbols-outlined text-lg">description</span>
              Generate Report Card
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
